INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00484', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '青青子佩，悠悠我思。縱我不往，子寧不來？（《詩經‧鄭風‧子衿》） 下列選項，何者不符合本詩所傳達的情感？', '["憶君心似西江水，日夜東流無歇時", "相思一夜梅花發，忽到窗前疑是君", "花紅易衰似郎意，水流無限似儂愁", "勸君更進一杯酒，西出陽關無故人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00485', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '涉江採芙蓉，蘭澤多芳草。採之欲遺誰，所思在遠道。還顧望舊鄉，長路漫浩浩。同心而離居，憂傷 以終老。（佚名〈涉江採芙蓉〉）這首詩所表現的情感是：', '["悲憤不已", "感傷思念", "歡喜自得", "感時憂國"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00486', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「舞蹈家羅曼菲學成歸國後，原本要去上班，但她突然想到：『如果我每天朝九晚五上班，就無法再上 那堂舞者必須上的課，我沒有辦法清楚地講那堂課是什麼？但是那堂課是每一個舞者的維他命，透過 這堂課，我感覺自己的精力，氣在走，我的精神狀態和身體狀態合而為一，我能掌握自己，跟自己擁 抱。因此，碰到現實上的挫折和悲傷，好像都不重要了。』」根據上文，下列敘述何者正確？', '["羅曼菲不當上班族，是因為厭煩朝九晚五的工作", "為了能掌握自己，跟自己擁抱，要去補習班上課", "吃維他命，可以讓舞者的精神狀態和身體狀態合而為一", "只要能持續當一位舞者，現實中的挫折和悲傷，都可以放下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00487', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「我試著將人對『情感』的接收，放入生活的脈絡裡討論，化約成一個簡單的條件，在孩子成長過程 中，父母、教師與教育工作者，和孩子之間的應對，創造出內心情感連結的條件，若是具有關鍵性的 影響，是否可以作為教育工作中主要的脈絡？從人的感受：憤怒、難過、害怕、緊張、高興、快樂…… 一直到讓人深層內在感受的價值、意義、自由、接納與愛，去啟動人內在最重要的生命力，呵護與養 成人的生命能量。」 根據上文，作者強調教育孩子最主要的脈絡是：', '["生活作息", "生命能量", "價值判斷", "情意感受"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00488', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「我知道有一日我的花冠也將凋落，／而我並不感到心驚。／因為花朵的美麗只是樹身的一部，／生 命的成長，蓬勃與凋萎，／一如星月依循著自然的軌道前行，／遠勝過花朵的歡欣的——／是我能成 為更大的樹，／蔭庇更多的行人，／承載更多的歌聲，／冬日來到——／我便褪下了枝葉，／無聲地 安息／而我驕傲於／我是一棵獨立的樹——／不是藤蘿。」 下列選項，何者符合上述文句所欲表達之主旨？', '["人事無常，無須執著", "自主意識，不求依附", "真摯情感，難以改變", "滄海桑田，轉眼成空"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00489', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '承上題，為何花朵凋落，文中的「我」卻不覺心驚？', '["安時處順，和光同塵", "花開花落，自然遞嬗", "春華秋實，必有收穫", "繁華落盡，終將幻滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00490', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「從沒聽說誰家的蟑螂咬傷了嬰兒的事情。日常潛入鳥籠鴿舍，也只撿點掉下來的糧食，絕不傷害鳥 兒。故我稱之為□，誰曰不宜！」 依文意推敲，上文□中最適合填入的選項是：', '["仁", "義", "禮", "智"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00491', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「六十五歲至一百歲都叫老，細分卻有霜紅之葉與枯木的差別；即使處於同一年齡層，一個充滿活力 視退休為第二個人生的開始，遂積極規劃、學習、籌備，展現出探險隊員一般的遠征樂趣，與一個自 覺日漸衰老、鑽入蝸牛老殼自怨自艾的人相比，其差異之大宛如星際。」這段話主要是要告訴我們：', '["我們要關心社會上有許多人過著自怨自艾的退休生活", "要有美好的退休生活，就要懂得欣賞霜紅之葉與枯木之美", "老人雖有年齡、體能狀態之分，但更關鍵的是自我的心態", "老人是社會的重要資產，人生經驗使他們有如探險隊員般的勇氣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00492', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「當你讀一本歷史書，讀到書中的古人面臨重要的抉擇關頭時，請你這時立刻把書蓋上。好好想一想， 如果你身處對方的位置時，你會如何決定？做什麼樣的決定？把一切都想清楚後，再把書打開，看看 這個人物是怎麼做的，他最後做了什麼樣的決定？他的決定帶來的是成功或是失敗？原因何在？然後 比較自己與古人，在選擇和方法上有何異同之處？」 本文主要強調閱讀歷史的方法是：', '["歸納", "思辨", "冥想", "演繹"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00493', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「他自承取筆名是為了不炫耀的緣故，他認為在那個年代，對於炫耀抱持著強烈敵意，一個擁有真實 能力的人，會有內在光芒吸引人去發現，絕對不能也不會敲鑼打鼓的在外炫耀。炫耀只會吸引一時， 膚淺的肯定，只會使人失去了繼續追求真實本事的毅力。躲在筆名後面，可以不用擔心是否浮誇地追 求不相稱的稱讚。他對女兒說：『或許你會慢慢理解，我當年躲在筆名後面躲避稱讚，那種幼稚卻真 誠的信念。』」 下列敘述，何者不符合文意？', '["有能力的人會有內在光芒吸引人去發現，不需炫耀", "膚淺的肯定，會使人失去繼續追求真實本事的毅力", "隱身筆名後面，躲避稱讚是一種幼稚不真誠的想法", "使用筆名，可以不用擔心是否浮誇地追求不相稱的稱讚"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
